import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { LayoutDashboard, Truck, Map, Settings, FileText } from 'lucide-react';

const Dashboard = ({ datos = [] }) => { // Agregamos un valor por defecto []

  // Validamos que datos sea un array antes de usar .length o .slice
  const safeDatos = Array.isArray(datos) ? datos : [];

  const dataGrafica = safeDatos.length > 0 ? safeDatos.slice(0, 8) : [
    { hora: '05:00', arribo: 400, bipeo: 240 },
    { hora: '07:00', arribo: 300, bipeo: 139 },
    { hora: '09:00', arribo: 200, bipeo: 980 },
  ];

  return (
    <div className="flex h-screen bg-[#0f172a] text-white font-sans">
      {/* SIDEBAR IZQUIERDO */}
      <div className="w-64 bg-[#1e293b] p-6 flex flex-col gap-4">
        <h1 className="text-blue-400 font-bold text-xl mb-8">MONITOR INHUB</h1>
        <NavItem icon={<LayoutDashboard size={20}/>} text="Command Center" active />
        <NavItem icon={<Truck size={20}/>} text="Fleet Status" />
        <NavItem icon={<Map size={20}/>} text="Route Logic" />
        <NavItem icon={<FileText size={20}/>} text="Reports" />
        <NavItem icon={<Settings size={20}/>} text="Settings" />
      </div>

      {/* CONTENIDO PRINCIPAL */}
      <div className="flex-1 p-8 overflow-y-auto">
        <header className="flex justify-between mb-8 border-b border-gray-700 pb-4">
          <h2 className="text-lg font-semibold uppercase tracking-wider">OCASA DASHBOARD</h2>
          <div className="text-green-400 text-sm">● SYSTEM STATUS: ACTIVE</div>
        </header>

        {/* TARJETAS SUPERIORES (KPIs) */}
        <div className="grid grid-cols-4 gap-6 mb-8">
          <KpiCard title="Global Efficiency" value="42.03%" sub="+2.4% vs prev hour" color="border-blue-500" />
          {/* Usamos safeDatos.length para evitar errores */}
          <KpiCard title="Total Piezas" value={safeDatos.length > 0 ? safeDatos.length.toLocaleString() : "42,750"} sub="Actualizadas" color="border-blue-300" />
          <KpiCard title="Pendientes" value="24,783" sub="En cola" color="border-orange-500" />
          <KpiCard title="Live Pulse" value="ACTIVE" sub="Node_IM_A" color="border-green-500" />
        </div>

        {/* GRÁFICA CENTRAL */}
        <div className="bg-[#1e293b] p-6 rounded-xl shadow-lg" style={{ height: '400px' }}>
          <h3 className="mb-6 font-medium text-gray-400">Kinetic Pulse Chart (Hourly)</h3>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={dataGrafica}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis dataKey="hora" stroke="#94a3b8" />
              <YAxis stroke="#94a3b8" />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px' }}
                itemStyle={{ color: '#fff' }}
              />
              <Bar dataKey="arribo" fill="#3b82f6" radius={[4, 4, 0, 0]} />
              <Bar dataKey="bipeo" fill="#93c5fd" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

// Sub-componentes
const NavItem = ({ icon, text, active }) => (
  <div className={`flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-colors ${active ? 'bg-blue-600' : 'hover:bg-gray-700'}`}>
    {icon} <span className="text-sm">{text}</span>
  </div>
);

const KpiCard = ({ title, value, sub, color }) => (
  <div className={`bg-[#1e293b] p-5 rounded-xl border-l-4 ${color} shadow-md`}>
    <p className="text-[10px] text-gray-400 uppercase mb-2 font-bold tracking-widest">{title}</p>
    <p className="text-2xl font-bold mb-1">{value}</p>
    <p className="text-[10px] text-gray-500">{sub}</p>
  </div>
);

export default Dashboard;
